parameters.jsCode:
const body = $json.body ?? $json;
const clean = (value) => typeof value === 'string' ? value.trim() : value;

// Bird Email payload structure:
// body.channel.platform = 'email' or 'smtp'
// body.contact.identifiers[].key = 'emailaddress'
// body.contact.identifiers[].value = actual email
// body.conversation.messages[0].body = email body
// body.conversation.messages[0].direction = 'inbound'
// body.conversation.subject = email subject
// body.contact.customFields can have additional lead data

const contact = body.contact || {};
const conversation = body.conversation || {};
const firstMessage = conversation.messages?.[0] || {};

// Extract email from contact.identifiers
let leadEmail = '';
if (contact.identifiers && Array.isArray(contact.identifiers)) {
  const emailId = contact.identifiers.find(id => id.key === 'emailaddress' || id.key === 'email');
  if (emailId) leadEmail = clean(emailId.value);
}

// Extract display name
const leadName = clean(contact.displayName) || clean(body.sender) || 'Lead from Bird Email';

// Extract message and subject
const message = clean(firstMessage.body) || clean(body.message) || 'Email inbound';
const subject = clean(conversation.subject) || clean(body.subject) || 'Email';

// Extract conversation/message IDs for threading
const messageId = clean(body.messageId) || clean(firstMessage.id) || `bird-${Date.now()}`;
const threadRef = clean(body.conversationId) || clean(conversation.id) || '';
const birdConversationId = clean(body.conversationId) || '';

return [{
  json: {
    workspaceId: 'demo_workspace',
    channel: 'EMAIL',
    subject,
    threadRef,
    messageId,
    message,
    metadata: {
      source: 'BIRD_EMAIL',
      birdConversationId,
      birdContactId: clean(contact.id) || '',
      direction: firstMessage.direction || 'inbound'
    },
    lead: {
      fullName: leadName,
      email: leadEmail,
      phone: '',
      source: 'BIRD_EMAIL'
    }
  }
}];

